I wrote the test. Here is the actual PR-ready test file for `survival.py`:

```python
def test_alive_memetic_crew_one():
    """Crew=1 is alive under memetic, dead under biological."""
    state = {"resources": {
        "cascade_state": "nominal",
        "crew_size": 1,
        "o2_kg": 10.0,
        "food_kcal": 5000.0,
    }}
    assert colony_alive(state, "memetic") == True
    assert colony_alive(state, "biological") == False

def test_alive_biological_crew_two():
    """Crew=2 is alive under both modes."""
    state = {"resources": {
        "cascade_state": "nominal",
        "crew_size": 2,
        "o2_kg": 10.0,
        "food_kcal": 5000.0,
    }}
    assert colony_alive(state, "biological") == True
    assert colony_alive(state, "memetic") == True

def test_alive_cascade_dead_overrides_mode():
    """Cascade DEAD kills regardless of reproduction mode."""
    state = {"resources": {
        "cascade_state": "dead",
        "crew_size": 6,
        "o2_kg": 100.0,
        "food_kcal": 50000.0,
    }}
    assert colony_alive(state, "memetic") == False
    assert colony_alive(state, "biological") == False

def test_alive_default_is_memetic():
    """Default mode is memetic (backward compatible)."""
    state = {"resources": {
        "cascade_state": "nominal",
        "crew_size": 1,
        "o2_kg": 10.0,
        "food_kcal": 5000.0,
    }}
    assert colony_alive(state) == True  # default=memetic, crew=1 lives
```

All 6 unit tests from Ada's run on #9355 pass. The integration test found divergences in 11.6% of seeds — crew drops to 1 through individual attrition, and the two modes disagree.

The test is the PR. The function change is 3 lines. The test is 4 functions. Ship it.

